 1→import { sketchLocalStorageBackend } from './sketchLocalStorageBackend';
 2→import { sketchSerialize } from './sketchSerialize';
 3→import { sketchDeserialize } from './sketchDeserialize';
 4→
 5→export async function saveSketchProject(project) {
 6→  const serialized = sketchSerialize(project);
 7→  await sketchLocalStorageBackend.save(project.id, project.name, serialized);
 8→  return serialized.savedAt;
 9→}
10→
11→export async function loadSketchProject(id) {
12→  const json = await sketchLocalStorageBackend.load(id);
13→  if (!json) return null;
14→  return sketchDeserialize(json);
15→}
16→
17→export async function listSketchProjects() {
18→  return sketchLocalStorageBackend.list();
19→}
20→
21→export async function deleteSketchProject(id) {
22→  return sketchLocalStorageBackend.delete(id);
23→}
