512→export function useSketch() {
513→  const ctx = useContext(SketchContext);
514→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
515→  const { state, dispatch } = ctx;
516→
517→  const getPart = useCallback(
518→    (partId) => state.project.parts.find((p) => p.id === partId) || null,
519→    [state.project.parts]
520→  );
521→
522→  const getAssembly = useCallback(
523→    (assemblyId) => state.project.assemblies.find((a) => a.id === assemblyId) || null,
524→    [state.project.assemblies]
525→  );
526→
527→  const getPartsForAssembly = useCallback(
528→    (assemblyId) => state.project.parts.filter((p) => p.assemblyId === assemblyId),
529→    [state.project.parts]
530→  );
531→
532→  const getChildParts = useCallback(
533→    (parentId) => state.project.parts.filter((p) => p.parentId === parentId),
534→    [state.project.parts]
535→  );
536→
537→  return {
538→    project: state.project,
539→    isDirty: state.isDirty,
540→    canUndo: state.history.length > 0,
541→    canRedo: state.future.length > 0,
542→    dispatch,
543→    getPart,
544→    getAssembly,
545→    getPartsForAssembly,
546→    getChildParts,
547→  };
548→}
