14→function SketchInner() {
15→  const { project, isDirty, dispatch } = useSketch();
16→  const { maximizedPanel, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
17→
18→  // Autosave
19→  useEffect(() => {
20→    if (!isDirty) return;
